// Redirect URL utilities
export const REDIRECT_PARAM = 'redirect';

export const createRedirectUrl = (baseUrl: string, redirectTo: string): string => {
    // Only add redirect parameter if redirectTo is not the root path
    if (redirectTo === Pathname.Root || !redirectTo) {
        return baseUrl;
    }
    // Use encodeURIComponent to properly encode the redirect URL with hash fragments
    return `${baseUrl}?${REDIRECT_PARAM}=${encodeURIComponent(redirectTo)}`;
};

export const getRedirectUrl = (searchParams: URLSearchParams, fallback: string = Pathname.Root): string => {
    const redirect = searchParams.get(REDIRECT_PARAM);
    if (redirect && redirect.startsWith('/')) {
        // Decode the URL parameter to handle hash fragments properly
        return decodeURIComponent(redirect);
    }
    return fallback;
};

